import anthropic
import json

client = anthropic.Anthropic()

response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=1024,
    system="You are a Python coding assistant.",
    messages=[
        {
            "role": "user",
            "content": "Write a Python function that adds two numbers.",
        }
    ],
    output_config={
        "format": {
            "type": "json_schema",
            "schema": {
                "type": "object",
                "properties": {
                    "function_name": {"type": "string"},
                    "code": {"type": "string"},
                    "explanation": {"type": "string"},
                },
                "required": ["function_name", "code", "explanation"],
                "additionalProperties": False,
            },
        }
    },
)

result = json.loads(response.content[0].text)

print("--- Structured Output ---")
print(f"Function: {result['function_name']}")
print(f"\nCode:\n{result['code']}")
print(f"\nExplanation: {result['explanation']}")

import json
from anthropic import Anthropic, beta_tool

client = Anthropic()

@beta_tool
def get_weather(location: str) -> str:
    """Get the weather for a given location.

    Args:
        location: The city and state, for example, San Francisco, CA

    Returns:
        A JSON-encoded string with the location, temperature, and weather condition.
    """
    return json.dumps(
        {
            "location": location,
            "temperature": "68°F",
            "condition": "Sunny",
        }
    )

# Use tool_runner to automatically handle tool calls
runner = client.beta.messages.tool_runner(
    max_tokens=1024,
    model="claude-opus-4-8",
    tools=[get_weather],
    messages=[
        {"role": "user", "content": "What is the weather in SF?"},
    ],
)

for message in runner:
    print(message)

import anthropic

client = anthropic.Anthropic()

# Define tool schema
tools = [
    {
        "name": "get_weather",
        "description": "Get the current weather in a given location",
        "input_schema": {
            "type": "object",
            "properties": {
                "location": {
                    "type": "string",
                    "description": "The city and state, e.g., San Francisco, CA"
                }
            },
            "required": ["location"]
        }
    }
]

# First request
response = client.messages.create(
    model="claude-opus-4-8",
    max_tokens=1024,
    tools=tools,
    messages=[{"role": "user", "content": "What's the weather in SF?"}],
)

# Check if Claude wants to use a tool
if response.stop_reason == "tool_use":
    for content in response.content:
        if content.type == "tool_use":
            tool_name = content.name
            tool_input = content.input

            # Execute tool
            if tool_name == "get_weather":
                result = get_weather(tool_input["location"])

            # Send result back
            response = client.messages.create(
                model="claude-opus-4-8",
                max_tokens=1024,
                tools=tools,
                messages=[
                    {"role": "user", "content": "What's the weather in SF?"},
                    {"role": "assistant", "content": response.content},
                    {"role": "user", "content": [
                        {"type": "tool_result", "tool_use_id": content.id, "content": result}
                    ]}
                ],
            )

print(response.content[0].text)

import anthropic

try:
    message = client.messages.create(
        max_tokens=1024,
        messages=[{"role": "user", "content": "Hello, Claude"}],
        model="claude-opus-4-8",
    )
except anthropic.APIConnectionError as e:
    print("The server could not be reached")
    print(e.__cause__)  # Underlying exception
except anthropic.RateLimitError as e:
    print("A 429 status code was received; back off a bit.")
except anthropic.APIStatusError as e:
    print("Another non-200 status code was received")
    print(e.status_code)
    print(e.response)
